-- Enrichment marathon batch: Mataroa, Material for MkDocs, Mathesar, Matomo, Mattermost, Mautic, Maxio, Mayan EDMS

-- ── Mataroa ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Mataroa is a minimalist blogging platform that strips away themes, analytics and social features so writers can focus purely on publishing markdown posts.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Premium is $9/year)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Solo / indie project$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Mataroa Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Mataroa review 2026: a minimalist markdown blogging platform with newsletters and comments. See features, $9/year premium pricing, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Mataroa is a minimalist blogging platform launched in 2020 by an independent developer as a deliberately simple alternative to full-featured blog software. It was inspired by Bear Blog and built around the philosophy that writing tools should get out of the way: there are no themes to configure, no built-in analytics, no algorithmic feeds, and no obtrusive subscribe popups. Writers compose posts in Markdown through a plain, distraction-free editor, and Mataroa renders each post on a clean, fast-loading static-feeling page. The platform is run as a small, sustainably-priced side project rather than a venture-backed company; the maintainer has publicly stated the service's monthly server costs are only a few euros, which is why pricing stays extremely low. Core free-tier features include unlimited blog posts, RSS feeds, drafts and scheduled posts, custom pages, syntax highlighting for code blocks, image uploads (capped at 1MB per image and 100MB total per account, with 100GB of annual bandwidth), a simple opt-in comment system that authors can moderate post by post, and an email newsletter feature that lets readers subscribe to receive new posts directly in their inbox as plain text emails. Every post can be exported at any time as Markdown files in a zip archive, reflecting Mataroa's strong stance against vendor lock-in. The paid Premium tier costs 9 US dollars per year and unlocks a custom domain (so a blog can be served from the author's own domain instead of a mataroa.blog subdomain) and automatic monthly email exports of all posts as a backup. There is no advertising, no tracking pixels, and no data resale; the company's own blog and marketing materials emphasize privacy and longevity over growth metrics. Mataroa targets individual writers, technical bloggers, hobbyists, and anyone who wants to publish quickly without wrestling with a CMS, choosing a theme, or worrying about SEO plugins. Its closest competitors are Bear Blog, Write.as, and to a lesser extent Ghost and micro.blog, all of which compete on simplicity and writer-first design rather than marketing or e-commerce features. Mataroa differentiates itself through its exceptionally low price point, plain-text export philosophy, integrated newsletter delivery at no extra cost on the free plan, and a codebase that is open source on GitHub, letting technically inclined users self-host or audit the platform. Because it deliberately omits analytics, A/B testing, monetization tools, and design customization, Mataroa is not intended for businesses running content marketing operations; it is built for individual voices who value permanence, portability, and minimal friction over growth tooling.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '207eb58f-a5bd-46b7-ad43-c35ea9d0fecf';

