-- ── Mathesar ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Mathesar is an open-source, self-hosted spreadsheet-like interface that lets non-technical and technical users view, edit and query PostgreSQL data directly.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); free tier available in early-beta Mathesar Cloud$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Nonprofit foundation, small team$q$, company_size),
  headquarters = COALESCE($q$United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Mathesar Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Mathesar review 2026: an open-source spreadsheet UI for Postgres. See features, self-hosted and cloud pricing, pros, cons, and alternatives like Airtable.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Mathesar is a free, 100 percent open-source, self-hosted user interface that gives spreadsheet-like access to PostgreSQL databases, letting users of any technical skill level view, edit, query and collaborate on relational data without writing SQL. The project began as an effort funded by a grant to explore better tools for working directly with Postgres, and its stewardship now sits with the Mathesar Foundation, a US-based 501(c)(3) nonprofit led by CEO and project lead Kriti Godey. In March 2024 the Mathesar Foundation received a 3 million dollar grant from the Reid Hoffman Foundation to support continued development, and the project is built on Django for its backend and works directly against native Postgres schemas, tables and access control rather than layering its own proprietary data model on top, which distinguishes it from spreadsheet-database hybrids that store data outside the source database. Because Mathesar reads and writes real Postgres tables, any data entered through its interface is immediately usable by other tools, applications and reports that already talk to that same Postgres instance, and Postgres's native roles and permissions carry through into Mathesar's access control. Core features include an Airtable-like grid view for browsing and editing rows, support for complex data types and constraints, the ability to link and explore relationships between tables, saved and shareable data explorations, and multi-user collaboration with granular permissions inherited from Postgres. Deployment is done via Docker or Docker Compose on a user's own infrastructure, keeping the project fully self-hostable, which the Foundation has stated is a permanent commitment. In addition to the self-hosted release, Mathesar Cloud launched as an early-beta hosted offering with a free workspace tier, aimed at users who want to try Mathesar against their data without installing or managing servers. Mathesar targets small businesses, nonprofits, researchers, government teams and internal tool builders who have data trapped in Postgres and want a no-code way to browse and manipulate it without asking a developer to write custom admin panels or SQL queries. Its closest competitors and points of comparison are Airtable, Baserow, NocoDB, and Postgres-specific admin tools like pgAdmin, Retool or Supabase's table editor. Mathesar differentiates itself by combining a fully open-source, self-hostable codebase with native Postgres compatibility (no data migration or proxy layer required), nonprofit governance rather than a venture-backed business model, and a stated mission to make structured data broadly interoperable and portable rather than locked into a proprietary SaaS format.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b425d59b-1c35-4d02-b5ba-62b13f0c3db7';

