-- ── Matomo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Matomo is an open-source, privacy-focused web analytics platform, formerly known as Piwik, that gives businesses 100 percent ownership of their visitor data.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted Community edition); Cloud plans from around EUR 29/month$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$Mid-size company (tens of employees)$q$, company_size),
  headquarters = COALESCE($q$Wellington, New Zealand$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$and 50+ localized languages$q$]::text[],
  seo_title = COALESCE($q$Matomo Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Matomo review 2026: the open-source, privacy-first Google Analytics alternative. Compare Cloud and on-premise pricing, features, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Matomo is an open-source web analytics platform originally released in 2007 by French developer Matthieu Aubry under the name Piwik, and officially rebranded to Matomo (Maori for 'insight') in January 2018. The company is headquartered in Wellington, New Zealand, and positions itself as the leading privacy-focused alternative to Google Analytics, installed on more than 1 million websites in over 190 countries as of recent counts. Matomo's core differentiator is data ownership: unlike Google Analytics, which processes data on Google's servers and uses it across its advertising ecosystem, Matomo can be self-hosted entirely on a customer's own infrastructure, or run in Matomo's own Cloud with data centers based in Frankfurt, Germany, giving European customers a way to keep analytics data within the EU for GDPR compliance. The platform is built to be a full digital analytics suite rather than just pageview tracking, offering website analytics, heatmaps and session recordings, funnels, A/B testing, form analytics, media analytics, marketing attribution, cohort analysis, tag management and a roll-up reporting dashboard for agencies managing multiple client sites. Because it is open source, Matomo also has a large plugin marketplace maintained by its community and third-party developers, letting users extend core functionality. Pricing follows two parallel tracks: Matomo Cloud, a fully managed SaaS offering starting around 29 euros per month for smaller traffic tiers and scaling with hit volume up to custom Enterprise pricing for very high-traffic sites, and Matomo On-Premise, where the Community edition is free forever for unlimited users and unlimited traffic when self-hosted, while paid on-premise tiers (Team, Business, Enterprise and VIP) add capacity, advanced features like cohorts, attribution and SAML/LDAP authentication, and support, generally priced from a few hundred to a few thousand euros per month depending on scale. Matomo targets privacy-conscious businesses, government agencies, universities, publishers and agencies operating in regulated markets (particularly the EU) who need GDPR- and cookie-law-compliant analytics without ceding data to a third-party ad platform. Its main competitors are Google Analytics 4, Plausible, Fathom Analytics, Adobe Analytics and Mixpanel. Matomo differentiates itself from lightweight privacy analytics tools like Plausible and Fathom by offering a much deeper analytics feature set (heatmaps, session recordings, funnels, A/B testing) comparable to Google Analytics or Adobe Analytics, combined with the option of full self-hosting and open-source auditability that neither Google nor Adobe offer.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f83fc3c6-361d-4fca-8f70-695fa0c9ab4f';

