-- ── Mayan EDMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Mayan EDMS is a free, open-source, Django-based document management system offering OCR, metadata indexing, workflow automation and electronic signature verification.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Small (creator-led, with commercial support available)$q$, company_size),
  headquarters = COALESCE($q$Puerto Rico, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$and multiple localized languages$q$]::text[],
  seo_title = COALESCE($q$Mayan EDMS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Mayan EDMS review 2026: an open-source, Django-based document management system with OCR and workflow automation. See features, pricing, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Mayan EDMS is a free and open-source electronic document management system (EDMS) originally created in 2010 by Roberto Rosario, a software developer and former Director of Software Development for the Government of Puerto Rico, who built the tool to help government agencies manage large volumes of permit and regulatory documents at a time when few open-source document management tools existed. The project is built with Python and Django and is designed to scale from small deployments to enterprise-scale repositories handling hundreds of millions of documents, typically deployed via Docker, Docker Compose or Kubernetes. Over more than a decade of continuous development, Mayan EDMS has accumulated over 200 releases and tens of thousands of commits from more than 100 contributors, making it one of the most mature open-source document management platforms available. Core functionality centers on ingesting, indexing, organizing and retrieving documents: the system supports custom metadata fields, color-coded tags, and cabinets (a folder-like organizational structure) so documents can be classified along multiple dimensions simultaneously rather than a single rigid hierarchy. Built-in Optical Character Recognition, powered by the Tesseract engine, extracts and indexes text from scanned documents and images in over 100 languages, and OCR processing can be distributed across multiple worker nodes for large-scale deployments. Mayan EDMS also includes document versioning, full-text search, an advanced workflow engine that tracks document state changes and can trigger automated actions as documents move through business processes, and electronic/digital signature capabilities, including verification of embedded cryptographic signatures and support for uploading detached signature files. More recent releases have added the ability to use large language model output (including OpenAI models) to help drive and automate the workflow engine for more agentic document processing. Mayan EDMS is released under the Apache 2.0 license, making it free to use, modify and redistribute without licensing fees; Roberto Rosario also offers commercial consulting, customization and support services for organizations that need paid assistance. The platform targets organizations that need to digitize and manage large volumes of documents with strict audit, retention and compliance requirements, including government agencies, legal and healthcare organizations, and any business replacing paper-based recordkeeping. Its main competitors include other open-source document management systems like Paperless-ngx and OpenKM, as well as commercial platforms like DocuWare, M-Files and SharePoint. Mayan EDMS differentiates itself through its combination of enterprise-scale architecture, built-in multi-language OCR, a flexible metadata-and-cabinet organizational model instead of rigid folders, and a fully open-source, self-hosted deployment model that avoids per-user or per-document licensing costs entirely.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b5c46acf-0f25-4f29-8713-c5083cd9eea5';

